$oldFolders = @("content\core-8","content\chaos","content\dwarfs","content\elves","content\greenskins","content\human","content\lustria","content\undead","content\unofficial","content\reference\skills","content\reference\spells"); foreach ($folder in $oldFolders) { if (Test-Path $folder) { $remaining = @(Get-ChildItem $folder -Recurse -File); if ($remaining.Count -eq 0) { Remove-Item $folder -Recurse -Force; Write-Host "  REMOVED: $folder" -ForegroundColor Magenta } else { Write-Host "  NOT EMPTY: $folder ($($remaining.Count) files remain)" -ForegroundColor Yellow; $remaining | ForEach-Object { Write-Host "    -> $($_.FullName)" -ForegroundColor Yellow } } } else { Write-Host "  ALREADY GONE: $folder" -ForegroundColor DarkGray } }
